#include<bits/stdc++.h>
using namespace std;
int n,m,d[2000010],head[2000010],cnt;
bool flag[2000010],instk[2000010];
vector<int> mp[2000010],mp1[2000010];
vector<int> ans[2000010];
stack<int> stk;
void dfs(int x)
{
    for(int i=head[x];i<mp[x].size();i++)
    {
        if(i<head[x])
        {
            i=head[x]-1;
            continue;
        }
        if(flag[mp1[x][i]])
        {
            head[x]=i+1;
            continue;
        }
        head[x]=i+1;
        flag[mp1[x][i]]=true;
        dfs(mp[x][i]);
    }
    if(instk[x])
    {
        cnt++;
        ans[cnt].push_back(x);
        while(stk.top()!=x)
        {
            ans[cnt].push_back(stk.top());
            instk[stk.top()]=false;
            stk.pop();
        }
        ans[cnt].push_back(x);
    }
    else
    {
        stk.push(x);
        instk[x]=true;
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v,s,t;
        scanf("%d%d%d%d",&u,&v,&s,&t);
        if(s==t)
        {
            continue;
        }
        mp[u].push_back(v);
        mp[v].push_back(u);
        mp1[u].push_back(i);
        mp1[v].push_back(i);
        d[u]++;
        d[v]++;
    }
    for(int i=1;i<=n;i++)
    {
        if(d[i]%2==1)
        {
            printf("NIE");
            return 0;
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(head[i]<mp[i].size())
        {
            dfs(i);
            instk[stk.top()]=false;
            stk.pop();
        }
    }
    printf("%d\n",cnt);
    for(int i=1;i<=cnt;i++)
    {
        printf("%d ",(int)(ans[i].size())-1);
        for(int j:ans[i])
        {
            printf("%d ",j);
        }
        printf("\n");
    }
    return 0;
}
